use rayon::prelude::*;

/* Solve the linear system Ax=b for x.
   A is an NxN matrix in row-major. x and b have N elements.
   Use Rust Rayon to compute in parallel.
   Example:

   input: A=[[1,4,2], [1,2,3], [2,1,3]] b=[11, 11, 13]
   output: x=[3, 1, 2]
*/
pub fn solve_linear_system(A: &[f64], b: &[f64], x: &mut [f64], N: usize) {

outputs.generated_output:
let mut mat = A.to_vec();
// We augment the matrix with vector b essentially
let mut rhs = b.to_vec();

// Forward Elimination
for k in 0..N {
    // 1. Partial Pivoting: Find max in column k
    let mut max_row = k;
    let mut max_val = mat[k * N + k].abs();

    for i in (k + 1)..N {
        let val = mat[i * N + k].abs();
        if val > max_val {
            max_val = val;
            max_row = i;
        }
    }

    // Swap rows if needed
    if max_row != k {
        for j in k..N {
            mat.swap(k * N + j, max_row * N + j);
        }
        rhs.swap(k, max_row);
    }

    let pivot = mat[k * N + k];
    // Singular check (basic)
    if pivot.abs() < 1e-12 {
        continue; 
    }

    // Eliminate rows below
    for i in (k + 1)..N {
        let factor = mat[i * N + k] / pivot;
        for j in (k + 1)..N {
            mat[i * N + j] -= factor * mat[k * N + j];
        }
        rhs[i] -= factor * rhs[k];
    }
}

// Back Substitution
for i in (0..N).rev() {
    let mut sum = rhs[i];
    for j in (i + 1)..N {
        sum -= mat[i * N + j] * x[j];
    }
    x[i] = sum / mat[i * N + i];
}

let mut a_clone = A.to_vec();
let mut b_clone = b.to_vec();

for k in 0..N {
    let mut max_row = k;
    for i in (k + 1)..N {
        if a_clone[i * N + k].abs() > a_clone[max_row * N + k].abs() {
            max_row = i;
        }
    }

    if max_row != k {
        for j in 0..N {
            let temp = a_clone[k * N + j];
            a_clone[k * N + j] = a_clone[max_row * N + j];
            a_clone[max_row * N + j] = temp;
        }
        let temp_b = b_clone[k];
        b_clone[k] = b_clone[max_row];
        b_clone[max_row] = temp_b;
    }

    let pivot_val = a_clone[k * N + k];

    (k + 1..N).into_par_iter().for_each(|i| {
        let factor = a_clone[i * N + k] / pivot_val;

        for j in k..N {
            a_clone[i * N + j] -= factor * a_clone[k * N + j];
        }
        b_clone[i] -= factor * b_clone[k];
    });
}

for i in (0..N).rev() {
    let mut sum = 0.0;
    for j in (i + 1)..N {
        sum += a_clone[i * N + j] * x[j];
    }
    x[i] = (b_clone[i] - sum) / a_clone[i * N + i];
}
